    category: 'Underworld',
  ),
  God(
    id: '292',
    name: 'Shikome',
    mythology: 'Japanese',
    title: 'Para Pengejar Buruk Rupa',
    titleEn: 'The Hags of Yomi',
    symbol: '👹',
